/**
 * @name Path traversal via taint flow from HTTP input to file system
 * @description User-controlled input flows to file system operations without proper validation
 * @kind path-problem
 * @problem.severity error
 * @id java/path-traversal-http
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module PathTraversalConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // File constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // Paths.get
    exists(MethodCall mc |
      mc.getMethod().hasName("get") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Paths") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // Path.resolve
    exists(MethodCall mc |
      mc.getMethod().hasName("resolve") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.nio.file", "Path") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // ClassPathResource constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("spark.resource", "ClassPathResource") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // ExternalResource constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("spark.resource", "ExternalResource") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // FileInputStream constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileInputStream") and
      sink.asExpr() = ce.getAnArgument()
    )
  }
}

module PathTraversalFlow = TaintTracking::Global<PathTraversalConfig>;
import PathTraversalFlow::PathGraph

from PathTraversalFlow::PathNode source, PathTraversalFlow::PathNode sink
where PathTraversalFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Path traversal: user input flows to file system operation from $@.", source.getNode(), "this user-controlled input"

/**
 * @name ExternalResourceHandler path traversal - no base directory containment verification
 * @description ExternalResourceHandler.getResource() builds file paths from HTTP input
 *              using UriPath.canonical() + addPaths(), but never verifies the resulting
 *              absolute path is within the configured staticFileFolder base directory.
 * @kind path-problem
 * @problem.severity error
 * @id java/external-handler-path-traversal
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-023
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ExternalPathTraversalConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // ExternalResource constructor where path from user input ends up
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("spark.resource", "ExternalResource") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // File constructor in ExternalResource or AbstractFileResolvingResource
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument() and
      (ce.getEnclosingCallable().getDeclaringType().hasQualifiedName("spark.resource", "ExternalResource") or
       ce.getEnclosingCallable().getDeclaringType().hasQualifiedName("spark.resource", "AbstractFileResolvingResource"))
    )
  }

  predicate isBarrier(DataFlow::Node node) {
    // Block if canonical path is obtained and compared
    exists(MethodCall mc |
      mc.getMethod().hasName("getCanonicalPath") and
      node.asExpr() = mc
    )
  }
}

module ExternalPathFlow = TaintTracking::Global<ExternalPathTraversalConfig>;
import ExternalPathFlow::PathGraph

from ExternalPathFlow::PathNode source, ExternalPathFlow::PathNode sink
where ExternalPathFlow::flowPath(source, sink)
select sink.getNode(), source, sink, 
  "Path traversal in ExternalResourceHandler: user input flows to ExternalResource/File without canonical path containment check from $@.",
  source.getNode(), "HTTP request input"
